import { useState, useReducer, useEffect, useLayoutEffect, useRef, useCallback, useMemo, useContext, createContext, useTransition, useDeferredValue, useId, useDebugValue } from &ldquo;react&rdquo;;
// ============================================================ // useContext + createContext — 全局主题管理 // ============================================================ const ThemeContext = createContext();
// ============================================================ // useReducer — 复杂状态管理（任务的增删改查） // ============================================================ const initialTasks = [ { id: 1, text: &ldquo;学习 React Hooks&rdquo;, done: true, priority: &ldquo;high&rdquo; }, { id: 2, text: &ldquo;构建任务管理应用&rdquo;, done: false, priority: &ldquo;high&rdquo; }, { id: 3, text: &ldquo;阅读官方文档&rdquo;, done: false, priority: &ldquo;medium&rdquo; }, { id: 4, text: &ldquo;写单元测试&rdquo;, done: false, priority: &ldquo;low&rdquo; }, ];
function taskReducer(state, action) { switch (action.type) { case &ldquo;ADD&rdquo;: return [&hellip;state, { id: Date.now(), text: action.text, done: false, priority: action.priority }]; case &ldquo;TOGGLE&rdquo;: return state.map(t =&gt; t.id === action.id ? { &hellip;t, done: !t.done } : t); case &ldquo;DELETE&rdquo;: return state.filter(t =&gt; t.id !== action.id); case &ldquo;CLEAR_DONE&rdquo;: return state.filter(t =&gt; !t.done); default: return state; } }
// ============================================================ // 自定义 Hook — useLocalStorage（内含 useDebugValue） // ============================================================ function useLocalStorage(key, initial) { const [value, setValue] = useState(() =&gt; { try { const stored = localStorage.getItem(key); return stored ? JSON.parse(stored) : initial; } catch { return initial; } });
// useDebugValue：在 DevTools 中显示调试信息 useDebugValue(value, v =&gt; ${key}: ${JSON.stringify(v).slice(0, 30)});
const set = useCallback((val) =&gt; { setValue(val); localStorage.setItem(key, JSON.stringify(val)); }, [key]);
return [value, set]; }
// ============================================================ // 主应用 // ============================================================ export default function App() { // useState — 控制主题 const [theme, setTheme] = useState(&ldquo;dark&rdquo;);
return ( // useContext Provider 包裹，传递主题 &lt;ThemeContext.Provider value={{ theme, setTheme }}&gt; &lt;/ThemeContext.Provider&gt; ); }
function TaskApp() { // useContext — 消费全局主题 const { theme, setTheme } = useContext(ThemeContext);
// useReducer — 管理任务列表 const [tasks, dispatch] = useReducer(taskReducer, initialTasks);
// useState — 输入框、优先级、搜索词 const [input, setInput] = useState(&quot;&quot;); const [priority, setPriority] = useState(&ldquo;medium&rdquo;); const [search, setSearch] = useState(&quot;&quot;);
// useLocalStorage (自定义Hook) — 持久化过滤条件 const [filter, setFilter] = useLocalStorage(&ldquo;task-filter&rdquo;, &ldquo;all&rdquo;);
// useRef — 自动聚焦输入框 const inputRef = useRef(null);
// useRef — 记录渲染次数（不触发重渲染） const renderCount = useRef(0); renderCount.current += 1;
// useTransition — 搜索为&quot;低优先级&quot;更新，保持输入流畅 const [isPending, startTransition] = useTransition();
// useDeferredValue — 延迟搜索词，避免频繁过滤 const deferredSearch = useDeferredValue(search);
// useId — 生成无障碍用的唯一 ID const inputId = useId(); const searchId = useId();
// useEffect — 页面标题随任务数变化 useEffect(() =&gt; { const undone = tasks.filter(t =&gt; !t.done).length; document.title = undone &gt; 0 ? (${undone}) 任务管理 : &ldquo;任务管理&rdquo;; return () =&gt; { document.title = &ldquo;任务管理&rdquo;; }; // 清理函数 }, [tasks]);
// useLayoutEffect — 任务新增后同步滚动到底部（需在绘制前执行） const listRef = useRef(null); useLayoutEffect(() =&gt; { if (listRef.current) { listRef.current.scrollTop = listRef.current.scrollHeight; } }, [tasks.length]);
// useMemo — 过滤 + 搜索计算，依赖不变时跳过 const filteredTasks = useMemo(() =&gt; { return tasks .filter(t =&gt; { if (filter === &ldquo;done&rdquo;) return t.done; if (filter === &ldquo;todo&rdquo;) return !t.done; return true; }) .filter(t =&gt; t.text.toLowerCase().includes(deferredSearch.toLowerCase())); }, [tasks, filter, deferredSearch]);
// useMemo — 统计数字 const stats = useMemo(() =&gt; ({ total: tasks.length, done: tasks.filter(t =&gt; t.done).length, todo: tasks.filter(t =&gt; !t.done).length, }), [tasks]);
// useCallback — 缓存提交函数，避免子组件重渲染 const handleAdd = useCallback(() =&gt; { if (!input.trim()) return; dispatch({ type: &ldquo;ADD&rdquo;, text: input.trim(), priority }); setInput(&quot;&quot;); inputRef.current?.focus(); }, [input, priority]);
// useCallback — 缓存搜索处理（搜索用 transition 包裹） const handleSearch = useCallback((e) =&gt; { startTransition(() =&gt; setSearch(e.target.value)); }, []);
const isDark = theme === &ldquo;dark&rdquo;;
const styles = { app: { minHeight: &ldquo;100vh&rdquo;, background: isDark ? &ldquo;linear-gradient(135deg, #0f0f1a 0%, #1a1a2e 50%, #16213e 100%)&rdquo; : &ldquo;linear-gradient(135deg, #f0f4ff 0%, #e8f0fe 50%, #dce8fb 100%)&rdquo;, fontFamily: &ldquo;&lsquo;Syne&rsquo;, &lsquo;Noto Sans SC&rsquo;, sans-serif&rdquo;, padding: &ldquo;0&rdquo;, display: &ldquo;flex&rdquo;, justifyContent: &ldquo;center&rdquo;, alignItems: &ldquo;flex-start&rdquo;, }, container: { width: &ldquo;100%&rdquo;, maxWidth: 680, padding: &ldquo;40px 24px 80px&rdquo;, }, header: { display: &ldquo;flex&rdquo;, justifyContent: &ldquo;space-between&rdquo;, alignItems: &ldquo;flex-start&rdquo;, marginBottom: 32, }, title: { fontSize: 36, fontWeight: 800, letterSpacing: &ldquo;-1.5px&rdquo;, color: isDark ? &ldquo;#e8eaf6&rdquo; : &ldquo;#1a237e&rdquo;, margin: 0, lineHeight: 1.1, }, subtitle: { fontSize: 13, color: isDark ? &ldquo;#7986cb&rdquo; : &ldquo;#5c6bc0&rdquo;, marginTop: 6, fontWeight: 500, letterSpacing: &ldquo;0.5px&rdquo;, }, themeBtn: { background: isDark ? &ldquo;rgba(121,134,203,0.15)&rdquo; : &ldquo;rgba(92,107,192,0.12)&rdquo;, border: 1px solid ${isDark ? &quot;rgba(121,134,203,0.3)&quot; : &quot;rgba(92,107,192,0.25)&quot;}, borderRadius: 12, padding: &ldquo;8px 16px&rdquo;, color: isDark ? &ldquo;#9fa8da&rdquo; : &ldquo;#5c6bc0&rdquo;, cursor: &ldquo;pointer&rdquo;, fontSize: 13, fontWeight: 600, transition: &ldquo;all 0.2s&rdquo;, }, statsRow: { display: &ldquo;flex&rdquo;, gap: 12, marginBottom: 28, }, statCard: (color) =&gt; ({ flex: 1, padding: &ldquo;14px 16px&rdquo;, borderRadius: 14, background: isDark ? rgba(${color}, 0.12) : rgba(${color}, 0.08), border: 1px solid rgba(${color}, 0.25), textAlign: &ldquo;center&rdquo;, }), statNum: (color) =&gt; ({ fontSize: 28, fontWeight: 800, color: rgb(${color}), lineHeight: 1, }), statLabel: { fontSize: 11, color: isDark ? &ldquo;#90a4ae&rdquo; : &ldquo;#78909c&rdquo;, marginTop: 4, fontWeight: 600, letterSpacing: &ldquo;0.8px&rdquo;, textTransform: &ldquo;uppercase&rdquo;, }, inputSection: { background: isDark ? &ldquo;rgba(255,255,255,0.04)&rdquo; : &ldquo;rgba(255,255,255,0.7)&rdquo;, border: 1px solid ${isDark ? &quot;rgba(255,255,255,0.08)&quot; : &quot;rgba(0,0,0,0.08)&quot;}, borderRadius: 18, padding: &ldquo;20px&rdquo;, marginBottom: 20, backdropFilter: &ldquo;blur(10px)&rdquo;, }, inputRow: { display: &ldquo;flex&rdquo;, gap: 10, marginBottom: 12, }, input: { flex: 1, background: isDark ? &ldquo;rgba(255,255,255,0.06)&rdquo; : &ldquo;rgba(0,0,0,0.04)&rdquo;, border: 1.5px solid ${isDark ? &quot;rgba(121,134,203,0.3)&quot; : &quot;rgba(92,107,192,0.2)&quot;}, borderRadius: 12, padding: &ldquo;11px 16px&rdquo;, color: isDark ? &ldquo;#e8eaf6&rdquo; : &ldquo;#1a237e&rdquo;, fontSize: 15, outline: &ldquo;none&rdquo;, fontFamily: &ldquo;inherit&rdquo;, transition: &ldquo;border-color 0.2s&rdquo;, }, addBtn: { background: &ldquo;linear-gradient(135deg, #5c6bc0, #7986cb)&rdquo;, border: &ldquo;none&rdquo;, borderRadius: 12, padding: &ldquo;11px 22px&rdquo;, color: &ldquo;white&rdquo;, fontSize: 15, fontWeight: 700, cursor: &ldquo;pointer&rdquo;, whiteSpace: &ldquo;nowrap&rdquo;, transition: &ldquo;opacity 0.2s, transform 0.1s&rdquo;, letterSpacing: &ldquo;0.3px&rdquo;, }, priorityRow: { display: &ldquo;flex&rdquo;, gap: 8, alignItems: &ldquo;center&rdquo;, }, priorityLabel: { fontSize: 12, color: isDark ? &ldquo;#78909c&rdquo; : &ldquo;#90a4ae&rdquo;, fontWeight: 600, letterSpacing: &ldquo;0.5px&rdquo;, }, priorityBtn: (p) =&gt; ({ padding: &ldquo;5px 14px&rdquo;, borderRadius: 8, border: 1.5px solid ${priority === p ? priorityColor(p) : &quot;transparent&quot;}, background: priority === p ? ${priorityColor(p)}22 : isDark ? &ldquo;rgba(255,255,255,0.05)&rdquo; : &ldquo;rgba(0,0,0,0.04)&rdquo;, color: priority === p ? priorityColor(p) : isDark ? &ldquo;#78909c&rdquo; : &ldquo;#90a4ae&rdquo;, cursor: &ldquo;pointer&rdquo;, fontSize: 12, fontWeight: 600, transition: &ldquo;all 0.15s&rdquo;, }), filterRow: { display: &ldquo;flex&rdquo;, gap: 8, marginBottom: 16, flexWrap: &ldquo;wrap&rdquo;, }, filterBtn: (active) =&gt; ({ padding: &ldquo;7px 18px&rdquo;, borderRadius: 10, border: &ldquo;none&rdquo;, background: active ? isDark ? &ldquo;rgba(121,134,203,0.25)&rdquo; : &ldquo;rgba(92,107,192,0.15)&rdquo; : &ldquo;transparent&rdquo;, color: active ? isDark ? &ldquo;#9fa8da&rdquo; : &ldquo;#5c6bc0&rdquo; : isDark ? &ldquo;#546e7a&rdquo; : &ldquo;#b0bec5&rdquo;, cursor: &ldquo;pointer&rdquo;, fontSize: 13, fontWeight: 600, transition: &ldquo;all 0.15s&rdquo;, }), searchInput: { width: &ldquo;100%&rdquo;, background: isDark ? &ldquo;rgba(255,255,255,0.05)&rdquo; : &ldquo;rgba(0,0,0,0.04)&rdquo;, border: 1.5px solid ${isDark ? &quot;rgba(255,255,255,0.08)&quot; : &quot;rgba(0,0,0,0.08)&quot;}, borderRadius: 12, padding: &ldquo;10px 16px&rdquo;, color: isDark ? &ldquo;#e8eaf6&rdquo; : &ldquo;#1a237e&rdquo;, fontSize: 14, outline: &ldquo;none&rdquo;, fontFamily: &ldquo;inherit&rdquo;, marginBottom: 16, boxSizing: &ldquo;border-box&rdquo;, }, taskList: { maxHeight: 380, overflowY: &ldquo;auto&rdquo;, display: &ldquo;flex&rdquo;, flexDirection: &ldquo;column&rdquo;, gap: 8, paddingRight: 4, }, taskItem: (done) =&gt; ({ display: &ldquo;flex&rdquo;, alignItems: &ldquo;center&rdquo;, gap: 12, padding: &ldquo;14px 16px&rdquo;, borderRadius: 14, background: isDark ? done ? &ldquo;rgba(255,255,255,0.02)&rdquo; : &ldquo;rgba(255,255,255,0.05)&rdquo; : done ? &ldquo;rgba(0,0,0,0.02)&rdquo; : &ldquo;rgba(255,255,255,0.8)&rdquo;, border: 1px solid ${isDark ? &quot;rgba(255,255,255,0.07)&quot; : &quot;rgba(0,0,0,0.07)&quot;}, cursor: &ldquo;pointer&rdquo;, transition: &ldquo;all 0.2s&rdquo;, opacity: done ? 0.55 : 1, }), checkbox: (done) =&gt; ({ width: 20, height: 20, borderRadius: 6, border: 2px solid ${done ? &quot;#7986cb&quot; : isDark ? &quot;#455a64&quot; : &quot;#b0bec5&quot;}, background: done ? &ldquo;linear-gradient(135deg, #5c6bc0, #7986cb)&rdquo; : &ldquo;transparent&rdquo;, display: &ldquo;flex&rdquo;, alignItems: &ldquo;center&rdquo;, justifyContent: &ldquo;center&rdquo;, flexShrink: 0, transition: &ldquo;all 0.2s&rdquo;, }), taskText: (done) =&gt; ({ flex: 1, fontSize: 15, color: isDark ? (done ? &ldquo;#546e7a&rdquo; : &ldquo;#cfd8dc&rdquo;) : (done ? &ldquo;#b0bec5&rdquo; : &ldquo;#37474f&rdquo;), textDecoration: done ? &ldquo;line-through&rdquo; : &ldquo;none&rdquo;, fontWeight: done ? 400 : 500, transition: &ldquo;all 0.2s&rdquo;, }), badge: (p) =&gt; ({ fontSize: 10, fontWeight: 700, letterSpacing: &ldquo;0.8px&rdquo;, color: priorityColor(p), background: ${priorityColor(p)}18, padding: &ldquo;2px 8px&rdquo;, borderRadius: 6, textTransform: &ldquo;uppercase&rdquo;, }), deleteBtn: { background: &ldquo;none&rdquo;, border: &ldquo;none&rdquo;, color: isDark ? &ldquo;#455a64&rdquo; : &ldquo;#cfd8dc&rdquo;, cursor: &ldquo;pointer&rdquo;, fontSize: 16, padding: &ldquo;2px 6px&rdquo;, borderRadius: 6, transition: &ldquo;color 0.15s&rdquo;, lineHeight: 1, }, footer: { display: &ldquo;flex&rdquo;, justifyContent: &ldquo;space-between&rdquo;, alignItems: &ldquo;center&rdquo;, marginTop: 20, padding: &ldquo;0 4px&rdquo;, }, renderCount: { fontSize: 11, color: isDark ? &ldquo;#37474f&rdquo; : &ldquo;#cfd8dc&rdquo;, fontWeight: 600, }, clearBtn: { background: &ldquo;none&rdquo;, border: 1px solid ${isDark ? &quot;rgba(255,255,255,0.1)&quot; : &quot;rgba(0,0,0,0.1)&quot;}, borderRadius: 8, padding: &ldquo;6px 14px&rdquo;, color: isDark ? &ldquo;#546e7a&rdquo; : &ldquo;#b0bec5&rdquo;, cursor: &ldquo;pointer&rdquo;, fontSize: 12, fontWeight: 600, transition: &ldquo;all 0.15s&rdquo;, }, pendingHint: { fontSize: 12, color: &ldquo;#7986cb&rdquo;, marginBottom: 8, height: 18, display: &ldquo;flex&rdquo;, alignItems: &ldquo;center&rdquo;, gap: 6, }, hookTag: { display: &ldquo;inline-block&rdquo;, fontSize: 10, fontWeight: 700, padding: &ldquo;2px 7px&rdquo;, borderRadius: 6, background: &ldquo;rgba(121,134,203,0.15)&rdquo;, color: &ldquo;#7986cb&rdquo;, letterSpacing: &ldquo;0.5px&rdquo;, marginLeft: 6, }, sectionLabel: { fontSize: 11, color: isDark ? &ldquo;#455a64&rdquo; : &ldquo;#cfd8dc&rdquo;, fontWeight: 700, letterSpacing: &ldquo;1px&rdquo;, textTransform: &ldquo;uppercase&rdquo;, marginBottom: 10, display: &ldquo;flex&rdquo;, alignItems: &ldquo;center&rdquo;, gap: 8, }, emptyState: { textAlign: &ldquo;center&rdquo;, padding: &ldquo;40px 0&rdquo;, color: isDark ? &ldquo;#37474f&rdquo; : &ldquo;#cfd8dc&rdquo;, fontSize: 14, }, };
return ( {/* 顶部标题 */} &lt;div style={styles.header}&gt; &lt;div&gt; &lt;h1 style={styles.title}&gt;任务管理器&lt;/h1&gt; &lt;div style={styles.subtitle}&gt;React Hooks 综合案例演示&lt;/div&gt; &lt;/div&gt; {/* useContext 消费主题 */} &lt;button style={styles.themeBtn} onClick={() =&gt; setTheme(isDark ? &quot;light&quot; : &quot;dark&quot;)}&gt; {isDark ? &quot;☀ 浅色&quot; : &quot;☾ 深色&quot;} &lt;/button&gt; &lt;/div&gt; {/* 统计卡片 — useMemo */} &lt;div style={styles.statsRow}&gt; {[ { label: &quot;全部&quot;, val: stats.total, color: &quot;121,134,203&quot; }, { label: &quot;待完成&quot;, val: stats.todo, color: &quot;255,167,38&quot; }, { label: &quot;已完成&quot;, val: stats.done, color: &quot;102,187,106&quot; }, ].map(s =&gt; ( &lt;div key={s.label} style={styles.statCard(s.color)}&gt; &lt;div style={styles.statNum(s.color)}&gt;{s.val}&lt;/div&gt; &lt;div style={styles.statLabel}&gt;{s.label}&lt;/div&gt; &lt;/div&gt; ))} &lt;/div&gt; {/* 添加任务 — useState + useRef + useCallback + useId */} &lt;div style={styles.inputSection}&gt; &lt;div style={styles.sectionLabel}&gt; 添加任务 &lt;span style={styles.hookTag}&gt;useState&lt;/span&gt; &lt;span style={styles.hookTag}&gt;useRef&lt;/span&gt; &lt;span style={styles.hookTag}&gt;useCallback&lt;/span&gt; &lt;span style={styles.hookTag}&gt;useId&lt;/span&gt; &lt;/div&gt; &lt;div style={styles.inputRow}&gt; &lt;label htmlFor={inputId} style={{ display: &quot;none&quot; }}&gt;任务内容&lt;/label&gt; &lt;input id={inputId} // useId 生成的无障碍 ID ref={inputRef} // useRef 访问 DOM style={styles.input} value={input} onChange={e =&gt; setInput(e.target.value)} onKeyDown={e =&gt; e.key === &quot;Enter&quot; &amp;&amp; handleAdd()} placeholder=&quot;输入任务内容，回车添加…&quot; /&gt; &lt;button style={styles.addBtn} onClick={handleAdd}&gt;+ 添加&lt;/button&gt; &lt;/div&gt; &lt;div style={styles.priorityRow}&gt; &lt;span style={styles.priorityLabel}&gt;优先级：&lt;/span&gt; {[&quot;high&quot;, &quot;medium&quot;, &quot;low&quot;].map(p =&gt; ( &lt;button key={p} style={styles.priorityBtn(p)} onClick={() =&gt; setPriority(p)}&gt; {p === &quot;high&quot; ? &quot;🔴 高&quot; : p === &quot;medium&quot; ? &quot;🟡 中&quot; : &quot;🟢 低&quot;} &lt;/button&gt; ))} &lt;/div&gt; &lt;/div&gt; {/* 搜索 — useTransition + useDeferredValue */} &lt;div style={styles.sectionLabel}&gt; 搜索与过滤 &lt;span style={styles.hookTag}&gt;useTransition&lt;/span&gt; &lt;span style={styles.hookTag}&gt;useDeferredValue&lt;/span&gt; &lt;span style={styles.hookTag}&gt;useMemo&lt;/span&gt; &lt;/div&gt; &lt;label htmlFor={searchId} style={{ display: &quot;none&quot; }}&gt;搜索任务&lt;/label&gt; &lt;input id={searchId} style={styles.searchInput} placeholder=&quot;🔍 搜索任务…&quot; onChange={handleSearch} // useTransition 包裹，低优先级更新 /&gt; {/* Transition 状态提示 */} &lt;div style={styles.pendingHint}&gt; {isPending &amp;&amp; &lt;&gt;&lt;span&gt;⏳&lt;/span&gt; 搜索中…&lt;/&gt;} &lt;/div&gt; {/* 过滤按钮 — useLocalStorage（自定义Hook） */} &lt;div style={styles.filterRow}&gt; {[ { key: &quot;all&quot;, label: &quot;全部&quot; }, { key: &quot;todo&quot;, label: &quot;待完成&quot; }, { key: &quot;done&quot;, label: &quot;已完成&quot; }, ].map(f =&gt; ( &lt;button key={f.key} style={styles.filterBtn(filter === f.key)} onClick={() =&gt; setFilter(f.key)}&gt; {f.label} &lt;/button&gt; ))} &lt;/div&gt; {/* 任务列表 — useReducer + useLayoutEffect */} &lt;div style={styles.sectionLabel}&gt; 任务列表 &lt;span style={styles.hookTag}&gt;useReducer&lt;/span&gt; &lt;span style={styles.hookTag}&gt;useLayoutEffect&lt;/span&gt; &lt;/div&gt; &lt;div ref={listRef} style={styles.taskList}&gt; {filteredTasks.length === 0 ? ( &lt;div style={styles.emptyState}&gt;暂无任务 ✨&lt;/div&gt; ) : ( filteredTasks.map(task =&gt; ( &lt;TaskItem key={task.id} task={task} isDark={isDark} styles={styles} onToggle={() =&gt; dispatch({ type: &quot;TOGGLE&quot;, id: task.id })} onDelete={() =&gt; dispatch({ type: &quot;DELETE&quot;, id: task.id })} /&gt; )) )} &lt;/div&gt; {/* 底部 */} &lt;div style={styles.footer}&gt; &lt;span style={styles.renderCount}&gt;渲染次数：{renderCount.current} 次（useRef 记录）&lt;/span&gt; {stats.done &gt; 0 &amp;&amp; ( &lt;button style={styles.clearBtn} onClick={() =&gt; dispatch({ type: &quot;CLEAR_DONE&quot; })}&gt; 清除已完成 &lt;/button&gt; )} &lt;/div&gt; &lt;/div&gt; &lt;/div&gt; ); }
// ============================================================ // 子组件 — 接收 useCallback 缓存的函数，避免不必要重渲染 // ============================================================ function TaskItem({ task, isDark, styles, onToggle, onDelete }) { return ( {task.done &amp;&amp; &lt;span style={{ color: &ldquo;white&rdquo;, fontSize: 12, lineHeight: 1 }}&gt;✓} {task.text} {task.priority === &ldquo;high&rdquo; ? &ldquo;高&rdquo; : task.priority === &ldquo;medium&rdquo; ? &ldquo;中&rdquo; : &ldquo;低&rdquo;} &lt;button style={styles.deleteBtn} onClick={e =&gt; { e.stopPropagation(); onDelete(); }} title=&ldquo;删除&rdquo; &gt;✕ ); }
function priorityColor(p) { return p === &ldquo;high&rdquo; ? &ldquo;#ef5350&rdquo; : p === &ldquo;medium&rdquo; ? &ldquo;#ffa726&rdquo; : &ldquo;#66bb6a&rdquo;; }
